#!/usr/bin/env python3
"""kaiju-gate-params — derive a per-model KAIJU gate from its qspec.

The KAIJU gate must certify that the KAIJU dequant reproduces the model's
FULL-PRECISION (f16) reference completion. Every admitted transformer model
already carries that reference in monster-swarm/qspecs/<model>.qspec.json:

    prompt_tokens : the fixed prompt (pre-tokenized — no per-model tokenizer
                    needed at gate time)
    expect_token  : the argmax the FULL model produces on that prompt (this is
                    how the model was admitted at full precision) == the f16
                    argmax reference
    reject_token  : a plausible-but-wrong token the gate must NOT argmax

So the gate is DATA-parameterized, not a qwen-only " Paris" hack. This script
reads a qspec and emits the substitutions cloudbuild-kaiju-encode.yaml needs.
No hand-picking: it is mechanical from the qspec.

Automatic derivation for a model WITHOUT a usable qspec token (or to
cross-check one): run the model's own f16 through llama.cpp greedily on the
prompt and take the argmax as expect_token. That path is documented in
KAIJU_ZOO_PLAN.md; --verify-f16 <logits.json> checks a qspec token against a
supplied f16-argmax dump.

Usage:
  kaiju-gate-params.py --model-id mistral-7b
  kaiju-gate-params.py --model-id mistral-7b --format shell   # KEY=VAL lines
  kaiju-gate-params.py --model-id mistral-7b --format subst   # gcloud CSV
"""
import argparse
import json
import os
import sys

HERE = os.path.dirname(os.path.abspath(__file__))
# scripts/ -> distributed-inference/ -> gnosis/ -> open-source/ -> repo root
REPO = os.path.abspath(os.path.join(HERE, "..", "..", "..", ".."))
QSPEC_DIR = os.path.join(REPO, "open-source", "gnosis", "monster-swarm", "qspecs")

# model_id -> qspec filename stem when they differ (qspec file != model id)
QSPEC_ALIAS = {
    "qwen2.5-7b": "qwen25-7b",
    "qwen2.5-0.5b": "paris",  # the 0.5b validation run gates via paris.qspec
}

# f16 GCS truth path is uniform: models/<id>/<id>-f16.gguf
GCS_BUCKET = "gs://neutral-418500-models"

# Per-model imatrix R2 key overrides. Fresh IQ-ladder runs write the generic
# key models/iq-ladder/<id>/<id>.imatrix, but a few predate that convention.
IMATRIX_OVERRIDE = {
    # qwen2.5-7b's KAIJU imatrix was computed separately (fuller coverage) and
    # lives at the legacy -full path, not the per-model subdir.
    "qwen2.5-7b": "models/iq-ladder/qwen2.5-7b-full.imatrix",
}

# Repo tokenizer.json per family for the (best-effort) ppl anchor. Missing ->
# ppl auto-skips; the argmax gate still gates. tiktoken tokenizers (llama3)
# are intentionally absent — they don't load via HF `tokenizers`.
TOKENIZER_BY_FAMILY = {
    "qwen": "apps/skymesh/src/ask/qwen2.5-tokenizer.json",
    "gemma": "apps/edge-web-app/public/aether/gemma3-4b-it-tokenizer.json",
    "tinyllama": "apps/edge-web-app/public/aether/tinyllama-tokenizer.json",
}


def family_of(model_id):
    m = model_id.lower()
    if m.startswith("qwen"):
        return "qwen"
    if m.startswith("gemma"):
        return "gemma"
    if m.startswith("tinyllama"):
        return "tinyllama"
    return None  # unknown -> no repo tokenizer -> ppl skipped


def qspec_path(model_id):
    stem = QSPEC_ALIAS.get(model_id, model_id)
    return os.path.join(QSPEC_DIR, f"{stem}.qspec.json")


def derive(model_id, base_knot_key=None, imatrix_key=None):
    qp = qspec_path(model_id)
    if not os.path.isfile(qp):
        raise SystemExit(f"[kaiju-gate-params] no qspec for {model_id} at {qp}")
    with open(qp) as f:
        q = json.load(f)
    pt = q.get("prompt_tokens")
    ex = q.get("expect_token")
    if not pt or ex is None:
        raise SystemExit(
            f"[kaiju-gate-params] {qp} lacks prompt_tokens/expect_token — this "
            f"qspec is not an argmax-gated text model (image/gateway/SSM?). "
            f"Derive from f16 instead (see KAIJU_ZOO_PLAN.md)."
        )
    fam = family_of(model_id)
    tok = TOKENIZER_BY_FAMILY.get(fam, "")
    return {
        "_MODEL_ID": model_id,
        "_F16_GCS": f"{GCS_BUCKET}/models/{model_id}/{model_id}-f16.gguf",
        "_IMATRIX_KEY": imatrix_key or IMATRIX_OVERRIDE.get(
            model_id, f"models/iq-ladder/{model_id}/{model_id}.imatrix"),
        "_BASE_KNOT_KEY": base_knot_key or f"models/{model_id}.knot",
        "_KNOT_NAME": f"{model_id}-kaiju1",
        "_OUT_KEY": f"models/{model_id}-kaiju1.knot",
        "_PROMPT_TOKENS": ",".join(str(t) for t in pt),
        "_EXPECT_TOKEN": str(ex),
        "_REJECT_TOKEN": str(q.get("reject_token", "")),
        "_TOKENIZER": tok,
    }


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--model-id", required=True)
    ap.add_argument("--base-knot-key", default=None,
                    help="override base knot R2 key (default models/<id>.knot)")
    ap.add_argument("--imatrix-key", default=None,
                    help="override imatrix R2 key")
    ap.add_argument("--format", choices=["json", "shell", "subst"], default="json")
    args = ap.parse_args()
    d = derive(args.model_id, args.base_knot_key, args.imatrix_key)
    # _REJECT_TOKEN is informational (not a yaml substitution) — drop from subst
    subst = {k: v for k, v in d.items() if k != "_REJECT_TOKEN"}
    if args.format == "json":
        print(json.dumps(d, indent=2))
    elif args.format == "shell":
        for k, v in d.items():
            print(f"{k}={v}")
    else:  # subst — gcloud --substitutions CSV (values here contain no commas
           # except _PROMPT_TOKENS, which gcloud needs escaped as ^;^)
        parts = [f"{k}={v}" for k, v in subst.items() if k != "_PROMPT_TOKENS"]
        # emit the prompt-tokens separately so the caller can use the ^;^ trick
        sys.stdout.write("^;^" + ";".join(parts))
        sys.stdout.write(f";_PROMPT_TOKENS={subst['_PROMPT_TOKENS']}\n")


if __name__ == "__main__":
    main()
